# Faktorial (iterasiya)
def factorial_iterative(n):
    result = 1
    for i in range(1, n + 1):
        result *= i
    return result

print(factorial_iterative(5))

# Faktorial (rekursiya)
def factorial_recursive(n):
    if n == 0 or n == 1:
        return 1
    return n * factorial_recursive(n - 1)

print(factorial_recursive(5))

# Fibonacci (rekursiv)
def fibonacci(n):
    if n <= 1:  # Baza şərti
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

print(fibonacci(6))

# Fibonacci (iterasiya ilə)
def fibonacci_iterative(n):
    if n <= 1:
        return n
    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b
    return b

print(fibonacci_iterative(6))

# Python kodu
def factorial(n):
    if n == 0 or n == 1:
        return 1
    return n * factorial(n - 1)

print(factorial(5))

// JavaScript kodu
function factorial(n) {
    if (n === 0 || n === 1) {
        return 1;
    }
    return n * factorial(n - 1);
}

console.log(factorial(5));

# Səhvlərdən qaçınma
def safe_factorial(n):
    try:
        if n == 0 or n == 1:
            return 1
        return n * safe_factorial(n - 1)
    except RecursionError:
        return 'Çox dərin rekursiya! İterasiyadan istifadə edin.'

print(safe_factorial(5))

