import sys
print(f'Rekursiya dərinliyi limiti: {sys.getrecursionlimit()}')

def deep_recursion(n):
    if n == 0:
        return 0
    return deep_recursion(n - 1) + 1

try:
    print(deep_recursion(1000))
except RecursionError:
    print('Maksimum rekursiya dərinliyi keçildi!')

# Ağac keçidi (rekursiv)
def traverse_tree(node):
    if not node:
        return
    print(node['value'])
    for child in node.get('children', []):
        traverse_tree(child)

tree = {
    'value': 'A',
    'children': [
        {'value': 'B', 'children': []},
        {'value': 'C', 'children': [{'value': 'D', 'children': []}]}
    ]
}

traverse_tree(tree)

